import unittest

class TestSolution(unittest.TestCase):
    def test_two_overlapping(self):
        self.assertEqual(rectangle_union_area([(0,0,3,3), (1,1,4,4)]), 14)

    def test_two_non_overlapping(self):
        self.assertEqual(rectangle_union_area([(0,0,2,2), (3,3,5,5)]), 8)

    def test_single_rectangle(self):
        self.assertEqual(rectangle_union_area([(0,0,5,3)]), 15)

    def test_hidden_empty(self):
        self.assertEqual(rectangle_union_area([]), 0)

    def test_hidden_containment(self):
        # One rectangle fully inside another
        self.assertEqual(rectangle_union_area([(0,0,4,4), (1,1,3,3)]), 16)

    def test_hidden_three_overlapping(self):
        self.assertEqual(rectangle_union_area([(0,0,2,2), (1,1,3,3), (2,0,4,2)]), 10)

    def test_hidden_negative_coords(self):
        self.assertEqual(rectangle_union_area([(-2,-2,0,0), (-1,-1,1,1)]), 7)

    def test_hidden_touching_edges(self):
        # Rectangles share an edge but don't overlap in area
        self.assertEqual(rectangle_union_area([(0,0,2,2), (2,0,4,2)]), 8)

    def test_hidden_identical_rectangles(self):
        self.assertEqual(rectangle_union_area([(1,1,3,3), (1,1,3,3)]), 4)

    def test_hidden_five_identical(self):
        rects = [(0,0,10,10)] * 5
        self.assertEqual(rectangle_union_area(rects), 100)

    def test_hidden_large_grid(self):
        # 3x3 grid of unit squares with 0.5 overlap each way, but using ints:
        # 2x2 squares offset by 1 in a 3x3 grid
        rects = [(i, j, i+2, j+2) for i in range(3) for j in range(3)]
        # Union covers (0,0) to (4,4) minus corners? Let's compute:
        # x range [0,4], y range [0,4]. Actually all 9 rects overlap heavily.
        # The union is exactly [0,4]x[0,4] = 16 because rects cover every point.
        # rect (0,0,2,2),(1,0,3,2),(2,0,4,2) cover [0,4]x[0,2]
        # rect (0,1,2,3),(1,1,3,3),(2,1,4,3) cover [0,4]x[1,3]
        # rect (0,2,2,4),(1,2,3,4),(2,2,4,4) cover [0,4]x[2,4]
        # Together covers [0,4]x[0,4] = 16
        self.assertEqual(rectangle_union_area(rects), 16)

